def test_compose_with_no_functions_returns_input_unchanged():
    fn = compose()
    assert fn(42) == 42
    assert fn("hello") == "hello"
    obj = {"a": 1}
    assert fn(obj) is obj


def test_compose_preserves_chained_transformation():
    def strip_text(x):
        return x.strip()

    def uppercase(x):
        return x.upper()

    def exclaim(x):
        return f"{x}!"

    fn = compose(exclaim, uppercase, strip_text)
    assert fn("  hello ") == "HELLO!"


